import{_ as t,o as l,c as e,a3 as r}from"./chunks/framework.DACwFHq9.js";const g=JSON.parse('{"title":"管理与导入导出","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/tools/llm-chat/quick-actions/management.md","filePath":"user-guide/tools/llm-chat/quick-actions/management.md","lastUpdated":1778239080000}'),o={name:"user-guide/tools/llm-chat/quick-actions/management.md"};function i(n,a,s,u,h,c){return l(),e("div",null,[...a[0]||(a[0]=[r('<h1 id="管理与导入导出" tabindex="-1">管理与导入导出 <a class="header-anchor" href="#管理与导入导出" aria-label="Permalink to &quot;管理与导入导出&quot;">​</a></h1><p>快捷操作管理器提供了一个直观的界面，用于组织和维护你的操作库。</p><h2 id="管理器界面" tabindex="-1">管理器界面 <a class="header-anchor" href="#管理器界面" aria-label="Permalink to &quot;管理器界面&quot;">​</a></h2><p>你可以通过侧边栏或设置菜单进入“快捷操作管理”：</p><ul><li><strong>左侧列表</strong>：管理快捷操作组（Set）。支持新建、重命名、克隆和批量删除。</li><li><strong>中间列表</strong>：管理组内的具体操作条目。</li><li><strong>右侧编辑器</strong>：编辑选定操作的名称、模板内容、自动发送开关及后处理规则。</li></ul><h2 id="分组与排序" tabindex="-1">分组与排序 <a class="header-anchor" href="#分组与排序" aria-label="Permalink to &quot;分组与排序&quot;">​</a></h2><ul><li><strong>组启用状态</strong>：你可以暂时禁用某个组，使其不在输入框的快速列表中显示。</li><li><strong>排序</strong>：系统会根据组的创建或更新时间进行默认排序。建议将最常用的操作放在独立的组中并保持启用。</li></ul><h2 id="导入与导出" tabindex="-1">导入与导出 <a class="header-anchor" href="#导入与导出" aria-label="Permalink to &quot;导入与导出&quot;">​</a></h2><p>为了方便分享和备份，快捷操作支持标准的 JSON 格式：</p><ul><li><strong>单组导出</strong>：导出选中的单个快捷操作组。</li><li><strong>批量导出</strong>：在“批量管理”模式下，勾选多个组一键导出为压缩包或合并的 JSON。</li><li><strong>导入</strong>： <ul><li>支持点击“导入”按钮选择文件。</li><li>支持将 JSON 文件直接拖入管理器界面的“投放区”实现快速导入。</li></ul></li></ul><h2 id="默认预设" tabindex="-1">默认预设 <a class="header-anchor" href="#默认预设" aria-label="Permalink to &quot;默认预设&quot;">​</a></h2><p>系统内置了两组常用的快捷操作：</p><ol><li><strong>代码助手</strong>：包含隐藏代码块包装、完整代码更新请求等。</li><li><strong>通用工具</strong>：包含 HTML 折叠标签包装、Markdown 引用包装等。</li></ol><hr><p><strong>相关阅读</strong>：</p><ul><li><a href="./">快捷操作概览</a></li><li><a href="./template-syntax">模板语法与宏联动</a></li></ul>',16)])])}const m=t(o,[["render",i]]);export{g as __pageData,m as default};
